return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=(n%10==1 && n%100!=11 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2);','language'=>'uk','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Будь ласка, оновіть плагін TranslatePress - Multilingual до версії %1$s або вище, щоб забезпечити коректну роботу %2$s.','Please install and activate the TranslatePress - Multilingual plugin'=>'Будь ласка, встановіть та активуйте плагін TranslatePress - Multilingual','Install & Activate'=>'Встановити та активувати','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Будь ласка, оновіть TranslatePress - Multilingual до версії %2$s або новішої. Ваша поточна встановлена версія TranslatePress - Multilingual більше не сумісна з поточною версією %1$s.','All TranslatePress functionalities are disabled until then.'=>'Усі функціональні можливості TranslatePress вимкнені доти.','Update Now'=>'Оновити зараз','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Це розширення TranslatePress було перенесено до основного плагіна і більше не використовується. Ви можете видалити його.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> потребує принаймні PHP версії 5.6.20+ для роботи. Це <a href="%s">мінімальна вимога останньої версії WordPress</a>. Будь ласка, зв\'яжіться з адміністратором вашого сервера, щоб оновити версію PHP.','Advanced'=>'Розширені','Settings saved.'=>'Налаштування збережено.','Are you sure you want to remove this item?'=>'Ви впевнені, що хочете видалити цей елемент?','Remove'=>'Видалити','Add'=>'Додати','Select...'=>'Вибрати...','[%s] Low TranslatePress AI Words'=>'[%s] Мало слів TranslatePress AI','upgrade your plan or get extra AI Words'=>'оновити план або отримати додаткові слова AI','upgrade your plan'=>'оновити план','TranslatePress AI words are running low on your site.'=>'На вашому сайті закінчуються слова TranslatePress AI.','Current status: %s words remaining'=>'Поточний стан: залишилось %s слів','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Якщо залишок слів AI закінчиться, автоматичний переклад через TranslatePress AI буде призупинено.','To continue translating your content, please %1$s over at %2$s'=>'Щоб продовжити переклад вашого вмісту, будь ласка, %1$s на %2$s','Manage Notification: %s'=>'Керувати сповіщенням: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Доступна нова версія %1$s. %2$sПереглянути деталі версії %3$s%4$s або %5$sоновити зараз%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Доступна нова версія %1$s. %2$sПереглянути деталі версії %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Щоб увімкнути оновлення, будь ласка, %1$sвведіть ваш ліцензійний ключ%2$s. Потрібен ліцензійний ключ? %3$sПридбайте його зараз%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Щоб увімкнути оновлення, будь ласка, перейдіть на %1$sсторінку ліцензії%2$s та перевірте, чи дійсна ваша ліцензія.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Щоб увімкнути оновлення, вашу ліцензію потрібно поновити. Будь ласка, перейдіть на сторінку %1$sTranslatePress Account%2$s та увійдіть, щоб поновити.','You do not have permission to install plugin updates'=>'У вас немає дозволу на встановлення оновлень плагінів.','Error'=>'Помилка','Your TranslatePress license key is invalid or missing.'=>'Ваш ліцензійний ключ TranslatePress недійсний або відсутній.','Your license key expired on %s.'=>'Термін дії вашого ліцензійного ключа закінчився %s.','Your license key has been disabled.'=>'Ваш ліцензійний ключ було вимкнено.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Ваш ліцензійний ключ вимкнено для цього URL. Увімкніть його знову на <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Керування сайтами.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Невідповідність ліцензійного ключа.</strong> Введена вами ліцензія не відповідає встановленій версії TranslatePress.</p><p>Будь ласка, перевірте, що ви встановили правильну версію для вашої ліцензії з вашого облікового запису TranslatePress.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Якщо у вас встановлено лише безкоштовний плагін, але ви додали платну ліцензію, будь ласка, встановіть платний плагін з вашого облікового запису TranslatePress.','Your license key has reached its activation limit.'=>'Ваш ліцензійний ключ досяг ліміту активацій.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Оновіть ваш тарифний план, щоб додати більше сайтів. %1$sОновити зараз%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Цей веб-сайт уже активовано за безкоштовною ліцензією. Кожен веб-сайт може використовувати лише одну безкоштовну ліцензію.','An error occurred, please try again.'=>'Сталася помилка, будь ласка, спробуйте ще раз.','You have successfully activated your license'=>'Ви успішно активували вашу ліцензію.','Others'=>'Інші','Restrict by Language'=>'Обмежити за мовою','Exclude from Language'=>'Виключити з мови','Restrict element to language'=>'Обмежити елемент мовою','Show this element only in one language.'=>'Показувати цей елемент лише на одній мові.','Enable translation'=>'Увімкнути переклад','Allow translation to the corresponding language only if the content is written in the default language.'=>'Дозволити переклад на відповідну мову лише за умови, що вміст написано мовою за замовчуванням.','Select language'=>'Вибрати мову','Choose in which language to show this element.'=>'Виберіть, якою мовою показувати цей елемент.','Exclude element from language'=>'Виключити елемент із мови','Exclude this element from specific languages.'=>'Виключити цей елемент із певних мов.','Select languages'=>'Вибрати мови','Choose from which languages to exclude this element.'=>'Виберіть, із яких мов виключити цей елемент.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Цей елемент залишатиметься видимим під час перекладу вашого вебсайту в редакторі перекладів.','The content of this element should be written in the default language.'=>'Вміст цього елемента має бути написано мовою за замовчуванням.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> виявив помилки SQL. <a href="%s" title="View TranslatePress SQL Errors">Перегляньте помилки</a>.','Automatic translation has been disabled.'=>'Автоматичний переклад вимкнено.','Dismiss this notice.'=>'Приховати це сповіщення.','Logged errors'=>'Зареєстровані помилки','These are the most recent 5 errors logged by TranslatePress:'=>'Це 5 останніх помилок, зареєстрованих TranslatePress:','Yes'=>'Так','Why are these errors occuring'=>'Чому виникають ці помилки','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Якщо TranslatePress виявить щось не так під час виконання запитів до вашої бази даних, він може вимкнути функцію автоматичного перекладу, щоб уникнути додаткових стягнень коштів з боку Google/DeepL. Автоматичний переклад потрібно ввімкнути вручну після вирішення проблем.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Виявлені помилки SQL можуть виникати з різних причин, зокрема через відсутність таблиць, відсутність дозволів для користувача SQL на створення таблиць або виконання інших операцій, проблеми після міграції сайту або зміни конфігурації сервера SQL.','What you can do in this situation'=>'Що ви можете зробити в цій ситуації','Plan A.'=>'План А.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Перейдіть до Налаштування -> TranslatePress -> вкладка Загальні та Збережіть налаштування. Це відновить таблиці з використанням ваших поточних налаштувань SQL. Перевірте, чи не виникає більше помилок під час перегляду вашого веб-сайту перекладеною мовою. Зверніть увагу на позначки часу помилок, щоб переконатися, що ви бачите не старі помилки. Відображаються лише 5 найновіших помилок.','Plan B.'=>'План Б.','If your problem isn\'t solved, try the following steps:'=>'Якщо вашу проблему не вирішено, спробуйте виконати такі кроки:','Create a backup of your database'=>'Створіть резервну копію вашої бази даних','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Створіть копію кожної таблиці перекладів, у якій ви зіткнулися з помилками. Ви можете скопіювати таблицю в межах тієї самої бази даних (наприклад, trp_dictionary_en_us_es_es_COPY) — виконуйте цей крок лише якщо ви хочете зберегти поточні переклади','Remove the trouble tables by executing the DROP function on them'=>'Видаліть проблемні таблиці, виконавши на них функцію DROP','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Перейдіть до Налаштування -> TranslatePress -> вкладка Загальні та Збережіть налаштування. Це відновить таблиці з використанням вашого поточного сервера SQL.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Скопіюйте відповідний вміст із дубльованих таблиць (наприклад, trp_dictionary_en_us_es_es_COPY) у щойно створену таблицю (trp_dictionary_en_us_es_es) — виконуйте цей крок лише якщо ви хочете зберегти поточні переклади','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Перевірте, чи все працює. Якщо щось пішло не так, ви можете відновити резервну копію, яку ви створили на першому кроці. Перевірте, чи не виникає більше помилок під час перегляду вашого веб-сайту перекладеною мовою. Зверніть увагу на позначки часу помилок, щоб переконатися, що ви бачите не старі помилки. Відображаються лише 5 найновіших помилок.','Plan C.'=>'План В.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Якщо вашу проблему досі не вирішено, спробуйте звернутися до свого хостинг-провайдера щодо ваших помилок. Найпоширенішою проблемою є відсутність дозволів для користувача SQL, зокрема дозволу на створення таблиць.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Не вдалося встановити. Повторіть спробу в <a href="%s" >панелі керування плагінами.</a>','Active'=>'Активний','Permission denied.'=>'У доступі відмовлено.','Invalid nonce.'=>'Недійсний nonce.','Settings scope unknown.'=>'Область налаштувань невідома.','Legacy disabled.'=>'Застарілий режим вимкнено.','Language Switcher'=>'Перемикач мови','Change language to %s'=>'Змінити мову на %s','Automatic Translation'=>'Автоматичний переклад','DeepL'=>'DeepL','Unsupported languages'=>'Непідтримувані мови','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Вибраний механізм автоматичного перекладу не підтримує ці мови.<br>Ви все ще можете перекладати сторінки цими мовами вручну за допомогою Редактора перекладів.','API key validation failed.'=>'Перевірку ключа API не виконано.','API key verification was successful.'=>'Перевірку ключа API успішно виконано.','Please enter your Google Translate key.'=>'Введіть свій ключ Google Translate.','Please enter your DeepL API key.'=>'Введіть свій ключ API DeepL.','Not TranslatePress onboarding page.'=>'Це не сторінка онбордингу TranslatePress.','Step %s does not exist'=>'Крок %s не існує','Welcome'=>'Вітаємо','Add Languages'=>'Додати мови','Enable Addons'=>'Увімкнути додатки','Finalize'=>'Завершити','Exit Setup'=>'Вийти з налаштування','Upgrade'=>'Покращити','Nothing here'=>'Тут нічого немає','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Ваша ліцензія <strong>TranslatePress</strong> відсутня або недійсна. <br/>Будь ласка, %1$sзареєструйте свою копію%2$s, щоб увімкнути автоматичний переклад сайту через TranslatePress AI, преміум-доповнення, автоматичні оновлення та підтримку. Потрібен ліцензійний ключ? %3$sПридбайте його зараз%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Ваша ліцензія <strong>TranslatePress</strong> закінчується %1$s. Будь ласка, %2$sоновіть свою ліцензію%3$s, щоб і надалі мати доступ до автоматичних перекладів через TP AI, преміум-доповнень, завантажень продуктів та автоматичних оновлень. %4$sОновити зараз%5$s','Error: '=>'Помилка: ','Something went wrong, please try again.'=>'Щось пішло не так, будь ласка, спробуйте ще раз.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Ваша ліцензія <strong>TranslatePress</strong> закінчилася. <br/>Будь ласка, %1$sоновіть свою ліцензію%2$s, щоб і надалі мати доступ до автоматичних перекладів через TranslatePress AI, преміум-доповнень, завантажень продуктів та автоматичних оновлень. %3$sОновити зараз %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Невідповідність ліцензійного ключа. Введена вами ліцензія не відповідає версії <strong>%1$s</strong>, яку ви встановили. <br/>Будь ласка, перевірте, чи ви встановили правильну версію для вашої ліцензії з вашого %2$sоблікового запису TranslatePress%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Якщо у вас встановлено лише безкоштовний плагін, але ви додали платну ліцензію, будь ласка, встановіть платний плагін з вашого облікового запису TranslatePress.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Ви досягли ліміту активації для вашої ліцензії <strong>%1$s</strong>. <br/>Керуйте своїми активними сайтами з %2$s вашого облікового запису %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Ваша ліцензія вимкнена для цього URL. Увімкніть її знову в <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Керування сайтами.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Для автоматичного перекладу %1$s потрібна активна ліцензія. Будь ласка, %2$sоновіть%3$s вашу ліцензію або придбайте нову %4$sтут%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Будь ласка, %1$sвведіть%2$s ваш ліцензійний ключ, щоб увімкнути автоматичний переклад %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'У вас залишилося менше ніж 5000 слів TranslatePress AI. Щоб продовжити автоматичний переклад вашого сайту, будь ласка, %sпридбайте додаткові слова AI зі знижкою в вашому обліковому записі%s.',' Error: '=>' Помилка: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Цей сайт уже активовано за безкоштовною ліцензією. Кожен сайт може використовувати лише одну безкоштовну ліцензію. Будь ласка, перейдіть на преміум-план, щоб отримати більше слів TranslatePress AI з %1$s вашого облікового запису %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'У вас немає дійсної ліцензії для <strong>TranslatePress</strong>. %1$sОтримайте її безкоштовно%2$s, щоб отримати доступ до TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>НОВЕ:</strong> Доповнення <strong>Different Domain per Language</strong> вже тут! Покращіть свою глобальну SEO та створіть локалізований досвід за допомогою доменів для конкретних країн, як-от .de або .fr. Перейдіть на <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business або Developer</a>, щоб отримати до нього доступ + інші преміум-переваги!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>НОВЕ:</strong> Доповнення <strong>Different Domain per Language</strong> вже тут! Покращіть свою глобальну SEO та створіть локалізований досвід за допомогою доменів для конкретних країн, як-от .de або .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Дізнатися більше</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Перевищено денну квоту символів машинного перекладу. Будь ласка, перевірте сторінку <strong>TranslatePress -> <a href="%s">Автоматичний переклад</a></strong> для отримання додаткової інформації.','Marketing optin'=>'Маркетингова підписка','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Дайте згоду на отримання сповіщень про оновлення безпеки та функцій, а також на збір нечутливих діагностичних даних.','TranslatePress Preferred User Language'=>'Бажана мова користувача TranslatePress','Preferred language to navigate the site'=>'Бажана мова для перегляду сайту','The language is automatically set based by the last visited language by the user.'=>'Мова автоматично встановлюється відповідно до останньої мови, обраної користувачем.','Always use this language'=>'Завжди використовувати цю мову','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Якщо ввімкнути цей параметр, бажана мова залишатиметься такою, як обрано вище, без можливості зміни на сайті.<br>Ця мова використовуватиметься в різних операціях, наприклад під час надсилання електронних листів користувачу.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Привіт! Схоже, ви вже деякий час використовуєте <strong>TranslatePress</strong> для перекладу свого сайту. Це чудово! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Якщо ви знайдете кілька хвилин, щоб оцінити його на WordPress.org, це дуже нам допоможе (і підвищить мою мотивацію).','~ Razvan, developer of TranslatePress'=>'~ Разван, розробник TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Оцінити TranslatePress на сторінці плагіна WordPress.org','Ok, I will gladly help!'=>'Гаразд, я з радістю допоможу!','No, thanks.'=>'Ні, дякую.','Full Language Names'=>'Повні назви мов','Short Language Names'=>'Короткі назви мов','Flags with Full Language Names'=>'Прапорці з повними назвами мов','Flags with Short Language Names'=>'Прапорці з короткими назвами мов','Only Flags'=>'Лише прапорці','Full Language Names No HTML'=>'Повні назви мов без HTML','Bottom Right'=>'Знизу справа','Bottom Left'=>'Знизу зліва','Top Right'=>'Зверху справа','Top Left'=>'Зверху зліва','Dark'=>'Темна','Light'=>'Світла','Deactivate'=>'Деактивувати','Activate'=>'Активувати','Invalid language code. Please try again.'=>'Неприпустимий код мови. Спробуйте ще раз.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Коди мови можуть містити лише символи A-Z a-z 0-9 - _. Перевірте коди мови в загальних налаштуваннях TranslatePress.','Error! Duplicate URL slug values.'=>'Помилка! Дубльовані значення URL slug.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Ви не можете вибрати дві мови, які мають однаковий <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">код ISO</a>, але різні формальності, оскільки це призведе до дублювання <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">тегів hreflang</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Виявлено дублікат мови.<br>Кожну мову можна додати лише один раз, щоб забезпечити точне керування перекладами.<br> Змініть дубльований запис мови та спробуйте ще раз. ','Current Language'=>'Поточна мова','Opposite Language'=>'Протилежна мова','General'=>'Загальні','Translate Site'=>'Перекласти сайт','Addons'=>'Додатки','License'=>'Ліцензія','Settings'=>'Налаштування','Activate License'=>'Активувати ліцензію','Pro Features'=>'Професійні функції','Need Help?'=>'Потрібна допомога?','Recent community discussions'=>'Останні обговорення спільноти','Loading...'=>'Завантаження...','Unable to load forum posts'=>'Не вдалося завантажити дописи форуму','Ask a Question'=>'Поставити запитання','View All Topics'=>'Переглянути всі теми','by'=>'від','Have a question?'=>'Маєте запитання?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Отримайте допомогу безпосередньо від розробників плагіна, запропонуйте покращення або поділіться відгуком!','Tip for faster help:'=>'Порада для швидшої допомоги:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Вкажіть, що ви спробували, чого очікували та що сталося. Скріншоти допомагають!','Toggle support chat'=>'Перемкнути чат підтримки','Ask the community'=>'Запитати спільноту','Close'=>'Закрити','Empty feed response'=>'Порожня відповідь стрічки','Unable to parse feed'=>'Не вдалося розібрати стрічку','Just now'=>'Щойно','%d hour ago'=>'%d годину тому' . "\0" . '%d години тому' . "\0" . '%d годин тому','%d day ago'=>'%d день тому' . "\0" . '%d дні тому' . "\0" . '%d днів тому','Source'=>'Джерело','Srcset'=>'Srcset','Alt attribute'=>'Атрибут alt','Title attribute'=>'Атрибут title','Anchor link'=>'Якірне посилання','Placeholder attribute'=>'Атрибут placeholder','Submit attribute'=>'Атрибут submit','Text'=>'Текст','Video Poster'=>'Постер відео','plural form'=>'Форма множини','one'=>'один','few'=>'декілька','many'=>'багато','other'=>'інше','Saved'=>'Збережено','Save'=>'Зберегти','Saving translation...'=>'Збереження перекладу...','You have unsaved changes!'=>'У вас є незбережені зміни!','Discard changes'=>'Відкинути зміни','Discard All'=>'Відкинути все','Loading Strings...'=>'Завантаження рядків...','Select string to translate...'=>'Виберіть рядок для перекладу...','Close Editor'=>'Закрити редактор','From'=>'З','To'=>'На','Add Media'=>'Додати медіа','Other languages'=>'Інші мови','Context'=>'Контекст','View Website As'=>'Переглянути сайт як','Available in our Pro Versions'=>'Доступно в наших Pro-версіях','Select or Upload Media'=>'Виберіть або завантажте медіа','Use this media'=>'Використати це медіа','Translate'=>'Перекласти','Translate entire block element'=>'Перекласти весь блок','Split block to translate strings individually'=>'Розділити блок, щоб перекладати рядки окремо','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Зберегти зміни перекладу. Комбінація: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Перейти до наступного рядка у спадному списку. Швидкий доступ: CTRL(⌘) + ALT + стрілка вправо','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Перейти до попереднього рядка у спадному списку. Швидкий доступ: CTRL(⌘) + ALT + стрілка вліво','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Скасувати всі зміни. Комбінація: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Скасувати зміни в цьому текстовому полі. Щоб скасувати зміни в усіх текстових полях, використовуйте комбінацію: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Закрити підказку','Quick Intro'=>'Коротке ознайомлення','Are you sure you want to split this phrase into smaller parts?'=>'Ви впевнені, що хочете розбити цю фразу на менші частини?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Цей рядок ще не готовий до перекладу. <br>Спробуйте знову за мить...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Щоб ця опція працювала, оновіть додаток Browse as other role до останньої версії.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Щоб перекладати slug, оновіть додаток SEO Pack до останньої версії.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Ви можете додати нову мову на сторінці <a href="%s">Налаштування->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Проте ви все ще можете використовувати TranslatePress, щоб <strong style="background: #f5fb9d;">змінювати рядки gettext</strong>, доступні на вашій сторінці.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Рядки, створені користувачем, не можна змінювати, лише ті, що з тем і плагінів.','Extra Translation Features'=>'Додаткові функції перекладу','Support for 130+ Extra Languages'=>'Підтримка 130+ додаткових мов','Access to TranslatePress AI'=>'Доступ до TranslatePress AI','Translate SEO Title, Description, Slug'=>'Перекласти SEO заголовок, опис та slug','Publish only when translation is complete'=>'Публікувати лише після завершення перекладу','Translate by Browsing as User Role'=>'Перекладати, переглядаючи як роль користувача','Different Menu Items for each Language'=>'Різні елементи меню для кожної мови','Automatic User Language Detection'=>'Автоматичне визначення мови користувача','Upgrade to PRO'=>'Оновити до PRO','Upgrade to PRO with our biggest discount of the year!'=>'Оновіть до PRO з нашою найбільшою знижкою року!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Цієї Чорної п\'ятниці отримайте доступ до цих функцій та інших за частку вартості:','No available suggestions'=>'Немає доступних пропозицій','Suggestions from translation memory'=>'Пропозиції з пам\'яті перекладів','Click to Copy'=>'Натисніть, щоб скопіювати','Human Translation'=>'Людський переклад','Machine Translation'=>'Машинний переклад','Text on this page is %s% translated into all languages.'=>'Текст на цій сторінці перекладено на всі мови на %s%.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% тексту на цій сторінці перекладено %2$s.','This page is %1$s% translated into %2$s.'=>'Ця сторінка перекладена %2$s на %1$s%.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'slug, який ви намагаєтесь редагувати, присутній в інших типах slug:%s%. Редагування замінить кожне входження, незалежно від поточного типу.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Наведіть курсор на будь-який текст на сторінці, натисніть %s,<br> а потім змініть переклад у бічній панелі.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Не забудьте зберегти переклад. Використовуйте комбінацію клавіш CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Змініть мову, щоб побачити зміни перекладу безпосередньо на сторінці.','Search for any text in this page in the dropdown.'=>'Шукайте будь-який текст на цій сторінці у випадному списку.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Ваша ліцензія %s <span class="trp-license-status-emphasized">прострочена</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Будь ласка, поновіть свою ліцензію, щоб і надалі мати доступ до TranslatePress AI, преміум-додатків, автоматичних оновлень і підтримки.','Renew Now'=>'Поновити зараз','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Цьої Чорної п\'ятниці поновіть свою ліцензію за спеціальною ціною</strong>, щоб і надалі мати доступ до завантажень продуктів, автоматичних оновлень і підтримки.','Get Deal'=>'Отримати пропозицію','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Ваша ліцензія %s була <span class="trp-license-status-emphasized">повернена</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Будь ласка, придбайте нову ліцензію, щоб і надалі мати доступ до TranslatePress AI, преміум-додатків, автоматичних оновлень і підтримки.','Purchase a new license'=>'Придбати нову ліцензію','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Ваша ліцензія %s <span class="trp-license-status-emphasized">відсутня або недійсна</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Будь ласка, введіть дійсну ліцензію, щоб отримати доступ до TranslatePress AI, преміум-додатків, автоматичних оновлень і підтримки. Потрібен ключ ліцензії? %1$sПридбати зараз%2$s','Enter a valid license'=>'Введіть дійсну ліцензію','Slugs'=>'Slug','Meta Information'=>'Метаінформація','String List'=>'Список рядків','Gettext Strings'=>'Рядки Gettext','Images'=>'Зображення','Videos'=>'Відео','Audios'=>'Аудіо','Dynamically Added Strings'=>'Динамічно додані рядки','Translation Editor'=>'Редактор перекладів','Edit translations by visually selecting them on each site page'=>'Редагуйте переклади, візуально вибираючи їх на кожній сторінці сайту','String Translation'=>'Переклад рядків','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Редагувати переклади URL slug, плагінів і тем (листи, форми тощо)','Current User'=>'Поточний користувач','Logged Out'=>'Вийшов із системи','Translate Page'=>'Перекласти сторінку','Add a New Language'=>'Додати нову мову','Get a Free AI License'=>'Отримати безкоштовну AI-ліцензію','Your License is Invalid'=>'Ваша ліцензія недійсна','Get More AI Words (%d left)'=>'Отримати більше AI-слів (залишилося %d)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Відкриває допис у редакторі перекладу. Допис має бути заздалегідь збережений як чернетка або опублікований.','Security check'=>'Перевірка безпеки','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Попередження:</strong> Деякі рядки містять символи з можливо некоректним кодуванням. Це може призвести до пошкодження запитів, і сторінка залишиться неперекладеною в робочому режимі. Рекомендуємо переглянути наведені нижче рядки або спосіб їх виведення.','TranslatePress data update'=>'Оновлення даних TranslatePress','We need to update your translations database to the latest version.'=>'Потрібно оновити базу даних перекладів до останньої версії.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Оновлення дозволить редагувати переклади локалізованого тексту з плагінів і теми. Наявні переклади й надалі працюватимуть як і раніше.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'ВАЖЛИВО: Настійно рекомендується спочатку створити резервну копію бази даних!
Ви впевнені, що хочете продовжити?','Run the updater'=>'Запустити оновлення','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Оновлення дозволить редагувати переклади ярликів. Існуючий переклад і надалі працюватиме належним чином.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Будь ласка, активуйте додаток SEO на сторінці<br/>WordPress -> Налаштування -> TranslatePress -> Додатки','Go to Addons'=>'Перейти до Додатків','The SEO Pack add-on allows translation of all the URL slugs:'=>'Додаток SEO Pack дозволяє перекладати всі URL-ярлики:','Taxonomy slugs'=>'Ярлики таксономій','Term slugs'=>'Ярлики термінів','Post slugs (this includes pages and custom post types)'=>'Ярлики записів (сюди входять сторінки та користувацькі типи записів)','Post type base slugs'=>'Базові ярлики типів записів','WooCommerce slugs'=>'Ярлики WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Додаток SEO Pack доступний у всіх преміум-версіях плагіна.','Upgrade to Pro'=>'Оновити до Pro','Description'=>'Опис','Article Section'=>'Розділ статті','Article Tag'=>'Мітка статті','OG Title'=>'Заголовок OG','OG Site Name'=>'Назва сайту OG','OG Description'=>'Опис OG','OG Image Alt'=>'Альт зображення OG','Twitter Title'=>'Заголовок Twitter','Twitter Description'=>'Опис Twitter','Twitter Image Alt'=>'Альт зображення Twitter','Page Title'=>'Заголовок сторінки','Dublin Core Title'=>'Заголовок Dublin Core','Dublin Core Description'=>'Опис Dublin Core','OG Image'=>'Зображення OG','OG Image Secure URL'=>'Безпечний URL зображення OG','Twitter Image'=>'Зображення Twitter','Removing cdata dictionary strings for language %s...'=>'Видалення рядків словника cdata для мови %s...','Removing untranslated dictionary links for language %s...'=>'Видалення неперекладених посилань словника для мови %s...','Removing duplicated gettext strings for language %s...'=>'Видалення дубльованих рядків gettext для мови %s...','Removing duplicated dictionary strings for language %s...'=>'Видалення дубльованих рядків словника для мови %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Видалення неперекладених рядків словника з наявним перекладом для мови %s...','Inserting original strings for language %s...'=>'Вставлення оригінальних рядків для мови %s...','Cleaning original strings table for language %s...'=>'Очищення таблиці оригінальних рядків для мови %s...','Updating original string ids for language %s...'=>'Оновлення ID оригінальних рядків для мови %s...','Regenerating original meta table for language %s...'=>'Перегенерація таблиці метаданих оригінальних рядків для мови %s...','Cleaning original meta table for language %s...'=>'Очищення таблиці метаданих оригінальних рядків для мови %s...','Replacing original id NULL with value for language %s...'=>'Заміна NULL ідентифікатора оригінального рядка на значення для мови %s...','Inserting gettext original strings for language %s...'=>'Вставлення оригінальних рядків gettext для мови %s...','Cleaning gettext original strings table for language %s...'=>'Очищення таблиці оригінальних рядків gettext для мови %s...','Updating gettext original string ids for language %s...'=>'Оновлення ID оригінальних рядків gettext для мови %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Міграція ярликів таксономій і базових ярликів типів записів до нової структури таблиці...','Migrating post slugs to new table structure for language %s...'=>'Міграція ярликів записів до нової структури таблиці для мови %s...','Migrating term slugs to new table structure for language %s...'=>'Міграція термінів slug до нової структури таблиць для мови %s...','Finishing up...'=>'Завершення...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Оптимізація бази даних завершилася невдало. Рекомендуємо відновити оригінальну базу даних або <a href="%s" >спробувати ще раз.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Оновлення перервано! Ваш обліковий запис не має повноважень для виконання оновлень бази даних.','Update aborted! Invalid nonce.'=>'Оновлення перервано! Недійсний nonce.','Update aborted! Incorrect action.'=>'Оновлення перервано! Неправильна дія.','Update aborted! Incorrect language code.'=>'Оновлення перервано! Неправильний код мови.','Updating database to version %s+'=>'Оновлення бази даних до версії %s+','Processing table for language %s...'=>'Обробка таблиці для мови %s...','Back to TranslatePress Settings'=>'Повернутися до налаштувань TranslatePress','Successfully updated database!'=>'Базу даних успішно оновлено!',' done.'=>' виконано.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Усі окремі плагіни-доповнення TranslatePress <a href="%1$s" target="_blank">були припинені</a> та тепер включені до преміум-версій TranslatePress Personal, Business і Developer. Будь ласка, увійдіть на свою <a href="%2$s" target="_blank">сторінку облікового запису</a>, завантажте нову преміум-версію та встановіть її. Ваші налаштування окремих доповнень буде перенесено.','Brand-new Language Switcher Settings are here!'=>'Зовсім нові налаштування перемикача мов вже тут!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Ознайомтеся з готовими шаблонами, змінюйте кольори, стилі прапорів, відступи, макети та багато іншого. Використовуйте живий перегляд, щоб за лічені секунди вдосконалити свій перемикач.','Start customizing'=>'Почати налаштування','Read documentation'=>'Читати документацію','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> потребує <strong><a href="http://php.net/manual/en/book.mbstring.php">бібліотеки PHP для роботи з багатобайтовими рядками</a></strong>. Будь ласка, зв\'яжіться з адміністратором вашого сервера, щоб встановити її на сервері.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Виявлено обмеження довгих запитів на хостингу WPEngine. Деякі великі сторінки можуть відображатися без перекладу. Ви можете зняти обмеження, додавши наступне до файлу wp-config.php вашого сайту: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Прапорець власної мови','The Language code of the added custom language cannot be empty.'=>'Код доданої власної мови не може бути порожнім.','The Language code of the added custom language is invalid.'=>'Код доданої власної мови недійсний.','The Automatic Translation Code of the added custom language is invalid.'=>'Код автоматичного перекладу доданої власної мови недійсний.','TranslatePress Add-ons'=>'Доповнення TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Спочатку ви повинні придбати цю версію, щоб отримати доступ до доповнення %1$sтут%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Будь ласка, спочатку %1$sвведіть ліцензійний%2$s ключ, щоб активувати цей додаток.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Для доступу до додатка потрібна активна ліцензія. Поновіть або придбайте нову %1$sтут%2$s.','Advanced Add-ons'=>'Розширені додатки','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Ці додатки розширюють ваш плагін перекладу та доступні в тарифах Developer, Business і Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Застарілий)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Підтримка SEO для slug сторінки, заголовка сторінки, опису та інформації соціального графа facebook і twitter. Атрибут HTML lang встановлено правильно.','Multiple Languages'=>'Кілька мов','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Додавайте стільки мов, скільки потрібно, щоб ваш проєкт став глобальним. Публікуйте мову лише тоді, коли всі переклади будуть готові.','Pro Add-ons'=>'Pro-додатки','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Ці додатки розширюють ваш плагін перекладу та доступні в тарифах Business і Developer.','DeepL Automatic Translation'=>'Автоматичний переклад DeepL','Automatically translate your website through the DeepL API.'=>'Автоматично перекладайте ваш сайт за допомогою DeepL API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Пропонує відвідувачам перейти на їхню бажану мову на основі налаштувань браузера або IP-адреси та запам’ятовує останню відвідану мову.','Translator Accounts'=>'Облікові записи перекладачів','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Створюйте облікові записи перекладачів для нових користувачів або дозвольте існуючим користувачам, які не є адміністраторами, перекладати ваш сайт.','Browse As User Role'=>'Перегляд як роль користувача','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Переглядайте свій сайт так, як це робила б певна роль користувача. Дуже корисно для динамічного контенту або прихованого контенту, який з’являється для певних користувачів.','Navigation Based on Language'=>'Навігація на основі мови','Configure different menu items for different languages.'=>'Налаштовуйте різні пункти меню для різних мов.','Different Domain per Language'=>'Окремий домен для кожної мови','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Підключіть окремі домени або субдомени до кожного перекладеного варіанту. Зміцніть локальну ідентичність свого бренду та покращіть SEO-показники для кожної мови, яку ви підтримуєте.','Recommended Plugins'=>'Рекомендовані плагіни','A short list of plugins you can use to extend your website.'=>'Короткий список плагінів, які ви можете використати для розширення вашого веб-сайту.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Збирайте більше інформації про користувачів у формі реєстрації за допомогою спеціальних полів профілю Profile Builder та/або додайте процес підтвердження електронної пошти, щоб верифікувати облікові записи ваших клієнтів.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Приймайте платежі від користувачів, створюйте плани передплати та обмежуйте доступ до контенту на вашому сайті членства.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Створюйте автоматизації та робочі процеси без коду на вашому сайті WordPress. Легко з’єднуйте свої плагіни, сайти та додатки між собою.','Save Changes'=>'Зберегти зміни','TranslatePress Errors'=>'Помилки TranslatePress','There are no logged errors.'=>'Немає зареєстрованих помилок.','Change language'=>'Змінити мову','Website language selector'=>'Перемикач мови веб-сайту','WordPress Translation Plugin'=>'Плагін перекладу для WordPress','Available languages'=>'Доступні мови','Language Switcher update notice'=>'Повідомлення про оновлення перемикача мов','Legacy language switcher is currently enabled'=>'Зараз увімкнено застарілий перемикач мов','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Ми оновили перемикач для розширеного налаштування та кращого досвіду користувачів.<br>Щоб використовувати новий конфігуратор, вимкніть <strong>Завантажувати застарілий перемикач мов</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Примітка: Ви можете повернутися будь-коли з <strong>Розширені налаштування → <a href="%s">Вирішення проблем</a></strong>.','Enable the new switcher'=>'Увімкнути новий перемикач','Your License Key is valid.'=>'Ваш ліцензійний ключ дійсний.','Your License Key is invalid.'=>'Ваш ліцензійний ключ недійсний.','Your License has expired.'=>'Термін дії вашої ліцензії минув.','Deactivate License'=>'Деактивувати ліцензію','Add a license key'=>'Додати ліцензійний ключ','License Key'=>'Ліцензійний ключ','Manage your license in your %1$s.'=>'Керуйте своєю ліцензією в розділі %1$s.','Account Page'=>'Сторінка облікового запису','Don’t have a TranslatePress AI License Key?'=>'Не маєте ліцензійного ключа TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Ви можете отримати його %1$sбезкоштовно%2$s, створивши безкоштовний обліковий запис. Це включає:','Access to TranslatePress AI for instant automatic translations'=>'Доступ до TranslatePress AI для миттєвих автоматичних перекладів','2000 AI words to translate automatically'=>'2000 слів для автоматичного перекладу','Get a free License Today'=>'Отримати безкоштовну ліцензію сьогодні','Debug Information'=>'Інформація для налагодження','Debug Data for License Checking'=>'Дані для налагодження перевірки ліцензії','Debug Data for License Activation'=>'Дані для налагодження активації ліцензії','Get more AI words and unlock all features with TranslatePress Pro.'=>'Отримайте більше слів для автоматичного перекладу та розблокуйте всі функції за допомогою TranslatePress Pro.','Upgrade now ↗'=>'Оновити зараз ↗','Already purchased a Premium version?'=>'Вже придбали преміум-версію?','Go to your %1$s'=>'Перейдіть до вашого %1$s','TranslatePress.com Account'=>'Обліковий запис TranslatePress.com','Download & Install the Pro plugin'=>'Завантажити та встановити плагін Pro','Learn More'=>'Докладніше','Get a translation volume estimate with a detailed breakdown per page'=>'Отримайте оцінку обсягу перекладу з детальним розбиттям за сторінками','Find how many translatable words are on your website'=>'Дізнайтеся, скільки слів для перекладу є на вашому сайті','Enable Automatic Translation'=>'Увімкнути автоматичний переклад','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Щоб використовувати <strong>DeepL</strong> для автоматичного перекладу, активуйте цей Pro-додаток на сторінці <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Автоматичний переклад за допомогою <strong>DeepL</strong> доступний як <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Оновившись, ви отримаєте доступ до всіх платних додатків, преміальної підтримки та допоможете фінансувати подальший розвиток TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Зверніть увагу, що використання DeepL API оплачується окремо. Дивіться <a href="https://www.deepl.com/pro.html#developer">інформацію про ціни DeepL</a>.','TranslatePress Pro Add-ons'=>'Додатки TranslatePress Pro','Test API credentials'=>'Перевірити облікові дані API','Check if the selected translation engine is configured correctly.'=>'Перевірити, чи правильно налаштований обраний механізм перекладу.','Alternative Engines'=>'Альтернативні механізми','Switch to TranslatePress AI'=>'Перейти на TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Інтегрувати машинний переклад безпосередньо з вашим сайтом WordPress.','More info'=>'Докладніше','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Оберіть механізм, який ви хочете використовувати, щоб %1$s автоматично перекласти ваш сайт.','Automatic Translation Settings'=>'Налаштування автоматичного перекладу','AI Words Low Notification'=>'Сповіщення про низьку кількість AI-слів','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Отримувати сповіщення електронною поштою, коли кількість слів TranslatePress AI опуститься нижче вказаного порогу.','This feature is only available when using the TranslatePress AI translation engine.'=>'Ця функція доступна лише при використанні механізму перекладу TranslatePress AI.','Notification Email'=>'Email для сповіщень','The email address where the low AI words notification will be sent.'=>'Адреса електронної пошти, на яку надходитиме сповіщення про низьку кількість AI-слів.','Word Threshold'=>'Поріг слів','words'=>'слів','You will be notified when remaining AI words drop below this number.'=>'Ви отримаєте сповіщення, коли залишок AI-слів опуститься нижче цього числа.','Automatically Translate Slugs'=>'Автоматично перекладати slug','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Автоматично генерувати переклади slug для записів, сторінок і користувацьких типів записів.<br/>Slug будуть автоматично перекладатися починаючи з другого оновлення кожної сторінки.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Ця функція доступна лише в платній версії. Оновіть TranslatePress та розблокуйте більше преміум-функцій.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Потрібно встановити та активувати <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">доповнення SEO Pack</a>.','Upgrade now'=>'Оновити зараз','Block Crawlers'=>'Блокувати краулери','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Заборонити краулерам ініціювати автоматичний переклад на вашому сайті.<br>Це не завадить краулерам отримувати доступ до сторінок цього сайту.','Limit machine translation / characters per day'=>'Обмеження машинного перекладу / символів на день','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Встановіть ліміт кількості символів автоматичного перекладу, щоб краще планувати бюджет вашого проєкту.','characters per day'=>'символів на день','Today\'s Character Count: '=>'Кількість символів за сьогодні: ','Log machine translation queries.'=>'Реєструвати запити машинного перекладу.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Увімкніть лише для тестування. Може вплинути на продуктивність.<br>Усі записи зберігаються в таблиці бази даних wp_trp_machine_translation_log. Використовуйте плагін на кшталт <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a>, щоб переглядати журнали, або безпосередньо з вашого менеджера баз даних (PHPMyAdmin тощо).','Test API Credentials'=>'Перевірити облікові дані API','HTTP Referrer: '=>'HTTP Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Використовуйте цей HTTP Referrer, якщо API дозволяє обмежити використання ключа з його панелі керування.','Response'=>'Відповідь','Response Body'=>'Тіло відповіді','Entire Response From wp_remote_get():'=>'Повна відповідь від wp_remote_get():','All Languages'=>'Усі мови','Select the languages you wish to make your website available in.'=>'Виберіть мови, якими ви хочете зробити свій вебсайт доступним.','Formality'=>'Формальність','Code'=>'Код','Slug'=>'Slug','Default'=>'За замовчуванням','Formal'=>'Формальний','Informal'=>'Неформальний','Language'=>'Мова','This language does not support formality. '=>'Ця мова не підтримує формальність. ','Are you sure you want to remove this language?'=>'Ви впевнені, що хочете видалити цю мову?','Custom Languages'=>'Користувацькі мови','To Add more languages activate the Multiple Languages Addon'=>'Щоб додати більше мов, активуйте додаток Multiple Languages','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Вам потрібна активна ліцензія, щоб додати більше мов. Перевірте у вашому %1$sобліковому записі%2$s, що ваша ліцензія дійсна.','Please %1$senter your license%2$s key first to add more languages.'=>'Будь ласка, спочатку %1$sвведіть ваш ліцензійний%2$s ключ, щоб додати більше мов.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Додавання більше ніж двох мов — платна функція. Оновіть TranslatePress і розблокуйте більше преміум-функцій.','Website Languages'=>'Мови сайту','Default Language'=>'Мова за замовчуванням','Select the language your content is written in.'=>'Виберіть мову, якою написано ваш вміст.','WARNING. Changing the default language will invalidate existing translations.'=>'УВАГА. Зміна мови за замовчуванням зробить наявні переклади недійсними.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Навіть зміна з en_US на en_GB, оскільки їх обробляють як дві різні мови.','In most cases changing the default flag is all it is needed: '=>'У більшості випадків достатньо змінити прапорець за замовчуванням: ','replace the default flag'=>'замінити прапорець за замовчуванням','Re-run Setup Wizard'=>'Повторно запустити майстер налаштування','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Майстер налаштування дозволяє швидко налаштувати TranslatePress. Ви можете запустити його в будь-який час.','Language Settings'=>'Налаштування мов','Use Native language name'=>'Використовувати рідну назву мови','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Позначте, якщо хочете відображати мови їхніми рідними назвами. Інакше мови відображатимуться англійською.','Use a subdirectory for the default language'=>'Використовувати підкаталог для мови за замовчуванням','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Позначте, якщо хочете додати підкаталог до URL-адреси для мови за замовчуванням.</br>Якщо позначити цей параметр, мовою за замовчуванням для відвідувачів веб-сайту стане перша у списку «Усі мови».','Force language in custom links'=>'Примусово встановлювати мову в користувацьких посиланнях','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Виберіть «Так», якщо хочете, щоб користувацькі посилання без мовного кодування зберігали поточну вибрану мову.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Використовуйте shortcode на будь-якій сторінці або у віджеті.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Ви також можете додати <a href="%s" title="Language Switcher Block Documentation">блок перемикача мов</a> у редакторі WP Gutenberg.','Menu item'=>'Пункт меню','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Перейдіть до  %1$s Зовнішній вигляд -> Меню%2$s, щоб додати мови до перемикача мов у будь-якому меню.','Learn more in our documentation.'=>'Дізнайтеся більше в нашій документації.','Floating language selection'=>'Плаваючий вибір мови','Add a floating dropdown that follows the user on every page.'=>'Додайте плаваючий випадаючий список, який супроводжує користувача на кожній сторінці.','Show "Powered by TranslatePress"'=>'Показувати "Powered by TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Показувати маленький напис "Powered by TranslatePress" у плаваючому перемикачі мов.','5 Days to Better Multilingual Websites'=>'5 днів до кращих багатомовних веб-сайтів','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sПриєднуйтесь до нашого БЕЗКОШТОВНОГО та ЕКСКЛЮЗИВНОГО вступного курсу%s та дізнайтеся, як збільшувати багатомовний трафік, виходити на міжнародні ринки та заощаджувати час і гроші, максимально використовуючи TranslatePress!','Invalid email address'=>'Неправильна адреса електронної пошти','Your email'=>'Ваша електронна пошта','Sign me up!'=>'Підписатися!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Підпишіться, вказавши свою адресу електронної пошти, та отримайте 5-частинний електронний посібник, який допоможе вам максимально розкрити потенціал TranslatePress.','Dismiss email course notification'=>'Відхилити сповіщення про електронний курс','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Привіт, %s,<br>Ніколи не пропускайте важливі оновлення - погодьтеся на отримання сповіщень про оновлення безпеки та функцій, а також на збір нечутливої діагностичної інформації.','Allow & Continue'=>'Дозволити та продовжити','Skip'=>'Пропустити','This will allow TranslatePress to:'=>'Це дозволить TranslatePress:','Your profile overview'=>'Огляд вашого профілю','Name and email address'=>'Ім\'я та адреса електронної пошти','Admin Notices'=>'Сповіщення адміністратора','Updates, announcements, marketing, no spam'=>'Оновлення, оголошення, маркетинг, без спаму','Plugin status & settings'=>'Статус і налаштування плагіна','Active, Deactivated, installed version and settings'=>'Активний, деактивований, встановлена версія та налаштування','Privacy Policy'=>'Політика конфіденційності','Terms of Service'=>'Умови використання','Support'=>'Підтримка','Documentation'=>'Документація','Add Extra AI Words'=>'Додати додаткові AI-слова','Optimize TranslatePress database tables'=>'Оптимізувати таблиці бази даних TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>ВАЖЛИВА ПРИМІТКА:</strong> Перед виконанням цієї дії наполегливо рекомендується спочатку створити резервну копію бази даних.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'ВАЖЛИВО: Наполегливо рекомендується спочатку створити резервну копію бази даних!! Ви впевнені, що хочете продовжити?','Operations to perform'=>'Операції для виконання','Remove CDATA for original and dictionary strings'=>'Видалити CDATA з оригінальних та словникових рядків','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Видаляє CDATA з таблиць trp_original_strings та trp_dictionary_*.<br>Цей тип вмісту не повинен визначатися TranslatePress. Його могло бути додано до бази даних у старіших версіях плагіна.','Remove untranslated links from dictionary tables'=>'Видалити неперекладені посилання з таблиць словника','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Видаляє неперекладені посилання та зображення з усіх таблиць trp_dictionary_*. Ці таблиці містять переклади для рядків, введених користувачем, таких як вміст запису, заголовок запису, меню тощо.','Remove duplicate rows for gettext strings'=>'Видалити дублікати для рядків gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Очищає всі таблиці trp_gettext_* від дублікатів рядків. Ці таблиці містять переклади для рядків тем і плагінів.','Remove duplicate rows for dictionary strings'=>'Видалити дублікати для словникових рядків','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Очищає всі таблиці trp_dictionary_* від дублікатів рядків. Ці таблиці містять переклади для рядків, введених користувачем, таких як вміст запису, заголовок запису, меню тощо.','Remove duplicate rows for original dictionary strings'=>'Видалити дублікати для оригінальних словникових рядків','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Очищає таблицю trp_original_strings від дублікатів рядків. Ця таблиця містить рядки мовою за замовчуванням без жодних перекладів.<br>Таблиця trp_original_meta, яка містить метаінформацію, що посилається на ID батьківського запису, також буде регенерована.<br>Такі дублікати можуть з\'являтися в рідкісних випадках непередбачуваної поведінки.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Замінити рядки gettext, у яких оригінальний ID дорівнює NULL, правильними оригінальними ID','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Виправляє проблему в рідкісному випадку, коли деякі рядки gettext мають оригінальний ID неправильно встановлено як NULL, що спричиняє проблеми в редакторі перекладів.<br>Ця операція виправляє оригінальні ID в таблицях trp_gettext_*.<br>Позначте цю опцію, лише якщо ви зіткнулися з проблемою в редакторі перекладів, коли натискання зеленого олівця не відкривало рядок gettext для перекладу в лівій бічній панелі.<br>В іншому випадку залиште цю опцію непозначеною, оскільки це ресурсомістка операція.','Optimize Database'=>'Оптимізувати базу даних','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Оновлення таблиць TranslatePress. Будь ласка, залиште це вікно відкритим.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Неактивні мови залишатимуться видимими та активними для адміністратора. Для інших користувачів вони не відображатимуться в перемикачах мов і також не будуть доступні.','unknown'=>'невідомо','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Додаток Extra Languages</strong> потребує TranslatePress версії %1$s або вищої. Зараз ви використовуєте версію %2$s. Будь ласка, оновіть TranslatePress, щоб увімкнути цю функцію.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Автоматичні та ручні зміни перекладу slug, виконані під час активної роботи <strong>TranslatePress - Multilingual</strong> 2.8.4, було видалено через деякі проблеми з цією версією. Усі переклади slug з попередніх версій тепер використовуються. Дякуємо за розуміння!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Якщо вони вам абсолютно необхідні, видалені переклади можна знайти в таблицях trp_slug_original_obsolete та trp_slug_translation_obsolete.','View Docs'=>'Переглянути документацію','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Призначити різні домени або субдомени для кожної мови. Коли відвідувачі заходять на ці домени, TranslatePress завантажує відповідний переклад відповідною мовою безпосередньо без перенаправлення.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Приклад: %1$s для англійської, %2$s для іспанської, %3$s для французької.','Before enabling:'=>'Перед увімкненням:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Переконайтеся, що ваші домени зареєстровані, спрямовані на ваш сервер і мають налаштовані SSL-сертифікати.','Domain'=>'Домен','Map this language to a different domain or sub-domain.'=>'Прив’яжіть цю мову до іншого домену або піддомену.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Заповнити поточним доменом','Check DNS'=>'Перевірити DNS','Checking DNS...'=>'Перевірка DNS...','DNS is correctly configured!'=>'DNS налаштовано правильно!','DNS check failed. Please verify your domain configuration.'=>'Перевірка DNS не вдалася. Будь ласка, перевірте конфігурацію домену.','This domain is already assigned to another language.'=>'Цей домен уже прив’язаний до іншої мови.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Додаток «Різний домен для кожної мови»</strong> вимагає версії TranslatePress %1$s або вищої. Зараз ви використовуєте версію %2$s. Будь ласка, оновіть TranslatePress, щоб увімкнути цю функцію.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Примітка: цю опцію вимкнено, коли активний додаток «Різний домен для кожної мови».','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Різний домен для кожної мови: домен обов’язковий, якщо увімкнено прив’язку домену. Перемикач вимкнено для мов із порожніми доменами.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Різний домен для кожної мови: один і той самий домен не можна призначати кільком мовам. Перемикач вимкнено для дублікатів доменів.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Різний домен для кожної мови: домен мови не може збігатися з основною URL-адресою сайту. Перемикач вимкнено для відповідного домену.','Please enter a domain.'=>'Будь ласка, введіть домен.','Invalid domain format.'=>'Неправильний формат домену.','Could not reach domain: %s'=>'Не вдалося отримати доступ до домену: %s','Domain returned HTTP status %d.'=>'Домен повернув HTTP-статус %d.','Domain is reachable!'=>'Домен доступний!','Limit this menu item to the following languages'=>'Обмежити цей пункт меню такими мовами','Date format'=>'Формат дати','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Налаштувати формат дати для кожної перекладеної мови.<br/>Залишити порожнім для типового налаштування WP або переглянути додаткову інформацію <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">тут</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Щоб редагувати наявну мову TranslatePress, введіть код мови та заповніть лише ті стовпці, які хочете перезаписати (наприклад, назва мови, прапор).<br>Ви також можете додати нові користувацькі мови. Вони будуть доступні в розділі Загальні налаштування, у списку Усі мови, де можна редагувати URL slug.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Для власного прапора спочатку завантажте зображення до медіабібліотеки, а потім вставте URL.<br>Зміна або видалення власної мови вплине на переклади та URL сайту.<br>Код мови та ISO-код мають містити лише літери, цифри, «-» та «_».<br>ISO-коди можна знайти на <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> та <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.','Language code'=>'Код мови','Language name'=>'Назва мови','Native name'=>'Рідна назва','ISO Code'=>'ISO-код','Flag URL'=>'URL прапора','Text RTL'=>'Текст справа наліво','Custom language'=>'Власна мова','Disable dynamic translation'=>'Вимкнути динамічний переклад','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Вимикає виявлення рядків, що динамічно відображаються за допомогою JavaScript. <br/>Рядки, завантажені через виклик AJAX на стороні сервера, все одно перекладатимуться.','Disable translation for gettext strings'=>'Вимкнути переклад для рядків gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Рядки Gettext — це рядки, які виводяться темами та плагінами. <br> Переклад цих типів рядків через TranslatePress може бути зайвим, якщо вони вже перекладені за допомогою системи файлів перекладу .po/.mo.<br>Увімкнення цієї опції може покращити швидкість завантаження сторінок вашого сайту в певних випадках. Недолік полягає в тому, що ви більше не зможете редагувати переклади gettext за допомогою TranslatePress, а також не зможете скористатися автоматичним перекладом цих рядків.','Gettext Strings translation is disabled'=>'Переклад рядків Gettext вимкнено','To enable it go to '=>'Щоб увімкнути його, перейдіть до ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Розширені налаштування->Налагодження->Вимкнути переклад для рядків gettext',' and uncheck the Checkbox.'=>' і зніміть позначку з прапорця.','Dismiss'=>'Відхилити','Exclude translated links from sitemap'=>'Виключити перекладені посилання з sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Не включати перекладені посилання у sitemaps, згенерованих плагінами SEO.<br/>Потребує, щоб <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> додаток SEO Pack</a> був встановлений та активований.','Disable post container tags for post title'=>'Вимкнути контейнерні теги для заголовка запису','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Це вимикає індексацію заголовка запису в перекладених мовах.<br/>Корисно, коли заголовок запису не підтримує HTML, що призводить до помилки на сторінці.','Disable post container tags for post content'=>'Вимкнути контейнерні теги для вмісту запису','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Це вимикає індексацію вмісту запису в перекладених мовах.<br/>Корисно, коли вміст запису не підтримує HTML, що призводить до помилки на сторінці.','Do not translate certain paths'=>'Не перекладати певні шляхи','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Виберіть, які шляхи можна перекладати. Підтримує символ підстановки наприкінці шляху.<br>Наприклад, щоб виключити https://example.com/some/path, ви можете використати правило /some/path/ або /some/*.<br>Вводьте кожне правило з нового рядка. Щоб виключити головну сторінку, використовуйте {{home}}.','Exclude Paths From Translation'=>'Виключити шляхи з перекладу','Translate Only Certain Paths'=>'Перекладати лише певні шляхи','Enable the hreflang x-default tag for language:'=>'Увімкнути тег hreflang x-default для мови:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Вмикає hreflang="x-default" для всієї мови. Докладніше дивіться в документації.','Translate numbers and numerals'=>'Перекладати числа та цифри','Enable translation of numbers ( e.g. phone numbers)'=>'Увімкнути переклад чисел ( наприклад, номерів телефонів)','Selector'=>'Селектор','Exclude from dynamic translation'=>'Виключити з динамічного перекладу','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Не перекладати динамічно рядки, що знаходяться у вузлах html, які відповідають цим селекторам.<br>Виключає з перекладу за допомогою JavaScript усі дочірні елементи вузлів HTML, що відповідають цим селекторам.<br/>Ці рядки все одно будуть перекладені на стороні сервера, якщо це можливо.','Gettext String'=>'Рядок Gettext','Exclude Gettext Strings'=>'Виключити рядки Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Виключити ці рядки з перекладу як рядки Gettext за допомогою TranslatePress. Залиште домен порожнім, щоб врахувати будь-який рядок Gettext.<br/>Їх все ще можна перекласти за допомогою файлів .po/.mo.','Exclude selectors only from automatic translation'=>'Виключити селектори лише з автоматичного перекладу','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Не перекладати автоматично рядки, що знаходяться у вузлах html, які відповідають цим селекторам.<br>Виключає з автоматичного перекладу всі дочірні елементи вузлів HTML, що відповідають цим селекторам.<br>Ручний переклад цих рядків все ще можливий.','Exclude selectors from translation'=>'Виключити селектори з перекладу','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Не перекладати рядки, що знаходяться у вузлах html, які відповідають цим селекторам.<br>Виключає з перекладу всі дочірні елементи вузлів HTML, що відповідають цим селекторам.<br>Ці рядки не можна перекласти ні вручну, ні автоматично.','String'=>'Рядок','Exclude strings from automatic translation'=>'Виключити рядки з автоматичного перекладу','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Не перекладати автоматично ці рядки (наприклад, імена, технічні терміни...)<br>Абзаци, що містять ці рядки, все одно будуть перекладені, окрім зазначеної частини.','Fix broken HTML'=>'Виправити пошкоджений HTML','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Загальна спроба виправити пошкоджений або відсутній HTML на перекладених сторінках.<br/>','Force slash at end of home url:'=>'Примусово додавати слеш у кінці домашнього URL:','Ads a slash at the end of the home_url() function'=>'Додає слеш у кінці функції home_url()','Show Both (recommended)'=>'Показувати обидва (рекомендовано)','Remove Country Locale'=>'Вилучити локаль країни','Remove Region Independent Locale'=>'Вилучити локаль без регіону','Remove duplicate hreflang'=>'Вилучити дублікати hreflang','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Оберіть, які теги hreflang відображатимуться на вашому сайті.<br/>Рекомендуємо показувати обидва типи тегів hreflang, як зазначено в <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">документації Google</a>.<br/>Вилучення локалі країни за наявності кількох локалей країн однієї мови (наприклад, English UK та English US) призведе до відображення одного тегу hreflang із посиланням лише на одну з регіональних локалей цієї мови.','Default (example: en-US, fr-CA, etc.)'=>'За замовчуванням (приклад: en-US, fr-CA тощо)','Regional (example: en, fr, es, etc.)'=>'Регіональний (приклад: en, fr, es тощо)','HTML Lang Attribute Format'=>'Формат атрибута lang HTML','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Змініть атрибут lang тега html на формат, що включає країну/регіон чи ні. <br>У HTML атрибут lang (<html lang="en-US">) слід використовувати для зазначення мови текстового вмісту, щоб браузер міг правильно відображати або обробляти ваш вміст (наприклад, для перенесення, стилізації, перевірки правопису тощо).','Load legacy Language Switcher'=>'Завантажувати застарілий перемикач мови','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Застосовується до всіх типів перемикачів мови (плаваючий, shortcode та меню). Якщо ввімкнено, сайт повернеться до використання оригінального перемикача мови, налаштованого на вкладці «Загальні налаштування», замінивши нову настроювану версію. Ваші наявні налаштування перемикача залишаться збереженими, але їх буде проігноровано, поки ця опція активна.','Load legacy SEO Pack Add-On'=>'Завантажувати застарілий додаток SEO Pack','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Якщо нещодавня міграція на новий перезапис slug спричиняє проблеми, встановіть це значення Так, щоб використовувати старий метод <br> Будь ласка, <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">відкрийте тікет підтримки</a>, повідомивши нас про проблеми, з якими ви зіткнулися.','Manual Translation Only'=>'Лише ручний переклад','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress проактивно сканує та зберігає рядки в базі даних, коли користувачі відвідують перекладені сторінки. <br>Це налаштування вимикає цю функціональність і дозволяє перекладати та зберігати рядки лише в Редакторі перекладів. <br>Також вимикає машинний переклад поза Редактором перекладів, надаючи кращий контроль над витратою символів, перекладаючи лише сторінки, які ви відвідуєте в Редакторі перекладів.','Open language switcher only on click'=>'Відкривати перемикач мови лише по кліку','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Відкривати перемикач мови shortcode клацанням замість наведення.<br> Закривати його клацанням по ньому, клацанням у будь-якому іншому місці екрана або натисканням клавіші Escape. Це вплине лише на перемикач мови shortcode.','Show opposite language in the language switcher'=>'Показувати протилежну мову в перемикачі мови','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Перетворює перемикач мови на кнопку, що показує іншу доступну мову, а не поточну.<br> Працює лише тоді, коли є рівно дві мови: мова за замовчуванням та мова перекладу.<br>Це вплине також на перемикач мови shortcode та плаваючий перемикач мови.<br> Щоб досягти цього в перемикачі мови меню, перейдіть у Зовнішній вигляд->Меню->Перемикач мови та виберіть Протилежну мову.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Натисніть тут</a>, щоб отримати доступ до інструмента оптимізації бази даних.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Це допомагає видалити можливі дублікати перекладів, очистити непотрібні дані та виправити можливі проблеми з метаданими.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Тут</a> ви можете переглянути останні 5 помилок SQL, пов’язаних із TranslatePress, якщо вони є.','Troubleshooting'=>'Вирішення проблем','Exclude Gettext strings'=>'Виключити рядки Gettext','Debug'=>'Налагодження','Custom languages'=>'Користувацькі мови','Miscellaneous options'=>'Різні налаштування','Exclude strings & pages'=>'Виключити рядки та сторінки','Automatic Translation Memory'=>'Автоматична пам\'ять перекладів','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Використовувати той самий переклад для схожого тексту. Рядки мають мати 95% схожості.<br>Допомагає запобігти втраті наявного перекладу під час виправлення помилок або незначних змін оригінального тексту. <br>Якщо переклад для дуже схожого оригінального рядка вже існує, його буде автоматично використано для поточного оригінального рядка.<br>Не працює під час внесення змін до тексту, який є частиною блоку перекладу, якщо новий текст не буде повторно об’єднано в блоці перекладу вручну.<br>Кожен рядок має містити щонайменше 50 символів.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'ПОПЕРЕДЖЕННЯ: Ця функція може негативно вплинути на час завантаження сторінок додатковими мовами, особливо з великими базами даних (наприклад, веб-сайти з великою кількістю сторінок або товарів). Якщо у вас спостерігається повільне завантаження, вимкніть це та спробуйте знову.','Fix missing dynamic content'=>'Виправити відсутній динамічний вміст','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Може допомогти виправити відсутній вміст, вставлений за допомогою JavaScript. <br> Показує динамічно вставлений вміст оригінальною мовою на мить до завершення запиту перекладу.','Filter Gettext wrapping from post content and title'=>'Фільтрувати обгортання Gettext із вмісту та заголовка запису','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Фільтрує обгортання gettext, такі як #!trpst#trp-gettext, з усього оновленого вмісту та заголовків записів. Не впливає на попередній вміст записів. <br/><strong>Перед увімкненням рекомендується створити резервну копію бази даних.</strong>','Filter Gettext wrapping from post meta'=>'Фільтрувати обгортання Gettext із метаданих запису','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Фільтрує обгортання gettext, такі як #!trpst#trp-gettext, з усіх оновлених метаданих записів. Не впливає на попередні метадані записів. <br/><strong>Перед увімкненням рекомендується створити резервну копію бази даних.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Ключ API Google Translate','Add your API Key here...'=>'Додайте свій ключ API тут...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Відвідайте <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">це посилання</a>, щоб дізнатися, як налаштувати ключ API, <strong>контролювати витрати на API</strong> та встановити обмеження HTTP referrer.','Your HTTP referrer is: %s'=>'Ваш HTTP referrer: %s','There was an error on the server processing your Google Translate key.'=>'Сталася помилка на сервері під час обробки вашого ключа Google Translate.','There was an error with your Google Translate key.'=>'Сталася помилка з вашим ключем Google Translate.','Please check your TranslatePress license key.'=>'Будь ласка, перевірте ваш ліцензійний ключ TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Для цього веб-сайту не виявлено активної ліцензії.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Щоб увімкнути автоматичний переклад за допомогою TranslatePress AI, вам потрібен ліцензійний ключ, який можна отримати, створивши безкоштовний обліковий запис.','Create your Free Account'=>'Створіть безкоштовний обліковий запис',' or '=>' або ','Enter your license key'=>'Введіть ключ ліцензії',' Or %1$spurchase one here%2$s'=>' Або %1$sпридбайте її тут%2$s','Your free account includes: '=>'Ваш безкоштовний обліковий запис включає: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Отримайте більше AI-слів і розблокуйте всі AI-функції за допомогою TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'У вас є дійсна <strong>ліцензія</strong> %s.',' words remaining. '=>' слів залишилося. ','Recheck'=>'Перевірити знову','Rechecking...'=>'Перевіряємо знову...','Done.'=>'Готово.','Manage your license & quota on the %s'=>'Керуйте своєю ліцензією та квотою на %s','TranslatePress.com Account Page'=>'Сторінка облікового запису TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Підтримка SEO для slug сторінки, заголовка сторінки, опису та інформації соціального графа Facebook і Twitter. Атрибут HTML lang установлено правильно.','Enable Modules'=>'Увімкнути модулі','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Увімкніть модулі-розширення, щоб розширити TranslatePress і покращити функціональність вашого перекладеного сайту.','More functionality with TranslatePress Pro.'=>'Більше функціональності з TranslatePress Pro.','Already a Pro User?'=>'Вже користувач Pro?','Activate License Key'=>'Активувати ліцензійний ключ','This add-on is not available on your current plan.'=>'Це розширення недоступне у вашому поточному тарифі.','Continue'=>'Продовжити','The link you followed has expired. Please reload the page and try again.'=>'Посилання, за яким ви перейшли, застаріло. Будь ласка, оновіть сторінку та спробуйте ще раз.','A valid license is required to enable Automatic Translation.'=>'Для ввімкнення автоматичного перекладу потрібна дійсна ліцензія.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Ваш ліцензійний ключ вимкнено для цієї URL-адреси. Увімкніть його знову на <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Керування сайтами.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Невідповідність ліцензійного ключа.</strong> Ліцензія, яку ви ввели, не відповідає встановленій версії TranslatePress.</p><p>Перевірте, чи встановлено правильну версію для вашої ліцензії з вашого облікового запису TranslatePress.</p>','Automatically translate your website using TranslatePress AI.'=>'Автоматично перекладайте свій веб-сайт за допомогою TranslatePress AI.','In order to enable Automatic Translation using Trans